--
-- Table structure for table `vehicle_template`
--

DROP TABLE IF EXISTS `vehicle_template`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `vehicle_template` (
  `template_id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `wvta_coc_no` varchar(100) NOT NULL COMMENT 'WVTA-COC编号',
  `coc_template_no` varchar(100) NOT NULL COMMENT 'COC模板号',
  `model_no` varchar(100) NOT NULL COMMENT '车型号',
  `version` varchar(50) NOT NULL DEFAULT '1' COMMENT '版本号',
  `vehicle_type` varchar(50) NOT NULL COMMENT '车辆类型(M1/M2/N1等)',
  `status` char(1) NOT NULL DEFAULT '0' COMMENT '状态(0=启用 1=停用)',
  `validate_result` char(1) DEFAULT NULL COMMENT '校验结果(0=未校验 1=通过 2=不通过)',
  `validate_time` datetime DEFAULT NULL COMMENT '最近校验时间',
  `validate_msg` text COMMENT '校验结果详情(JSON)',
  `json` longtext COMMENT 'COC模板字段内容(JSON)',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `del_flag` char(1) NOT NULL DEFAULT '0' COMMENT '删除标志(0=存在 2=删除)',
  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `filepath` varchar(400) DEFAULT NULL COMMENT '文件存储路径',
  `is_last` tinyint DEFAULT '1' COMMENT '是否最新版本',
  `uuid` varchar(100) DEFAULT NULL COMMENT '相同模板标识',
  `overdue_date` datetime DEFAULT NULL COMMENT '模板过期时间',
  `template_version` varchar(100) DEFAULT NULL COMMENT '非历史版本的那个版本',
  PRIMARY KEY (`template_id`),
  UNIQUE KEY `vehicle_template_unique` (`wvta_coc_no`,`coc_template_no`,`del_flag`,`version`),
  KEY `idx_coc_template_no` (`coc_template_no`),
  KEY `idx_model_no` (`model_no`)
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='COC模板主表';
/*!40101 SET character_set_client = @saved_cs_client */;

